class ListNode:
    def __init__(self, val=0, next=None):
        self.val, self.next = val, next

def _build_list(arr):
    """Build a singly linked list from a list of values."""
    head = ListNode(0); curr = head
    for v in arr:
        curr.next = ListNode(v); curr = curr.next
    return head.next

def _list_to_array(head):
    """Serialize a linked list back to an array of values."""
    out = []
    while head:
        out.append(head.val); head = head.next
    return out


def reverse_list(head):
    head = _build_list(head)
    # Your code — reverse the linked list and return the new head ListNode.
    # The test will serialize it back to an array.

    return _list_to_array(head)

class TreeNode:
    def __init__(self, val=0, left=None, right=None):
        self.val, self.left, self.right = val, left, right

def _build_tree(arr):
    """Build a binary tree from level-order array (None marks missing nodes)."""
    if not arr or arr[0] is None:
        return None
    root = TreeNode(arr[0])
    queue, i = [root], 1
    while queue and i < len(arr):
        node = queue.pop(0)
        if i < len(arr) and arr[i] is not None:
            node.left = TreeNode(arr[i]); queue.append(node.left)
        i += 1
        if i < len(arr) and arr[i] is not None:
            node.right = TreeNode(arr[i]); queue.append(node.right)
        i += 1
    return root

def _serialize_tree(root):
    """Serialize a binary tree to level-order array, trimming trailing Nones."""
    if not root: return []
    out, queue = [], [root]
    while queue:
        node = queue.pop(0)
        if node is None:
            out.append(None)
        else:
            out.append(node.val)
            queue.append(node.left)
            queue.append(node.right)
    while out and out[-1] is None:
        out.pop()
    return out


