class Node:
    def __init__(self, val=0, neighbors=None):
        self.val = val
        self.neighbors = neighbors if neighbors is not None else []

def _build_graph(adj_list):
    """Build an undirected graph from a 1-indexed adjacency list."""
    if not adj_list: return None
    nodes = [Node(i + 1) for i in range(len(adj_list))]
    for i, neighbors in enumerate(adj_list):
        nodes[i].neighbors = [nodes[j - 1] for j in neighbors]
    return nodes[0]

def _graph_to_adj_list(node):
    """Serialize a graph (any reachable Node) back to a 1-indexed adjacency list."""
    if not node: return []
    visited = {node.val: node}
    queue = [node]
    while queue:
        n = queue.pop(0)
        for nb in n.neighbors:
            if nb.val not in visited:
                visited[nb.val] = nb
                queue.append(nb)
    return [
        sorted(nb.val for nb in visited[v].neighbors)
        for v in sorted(visited.keys())
    ]


def clone_graph(adj_list):
    node = _build_graph(adj_list)
    # Your code — return a deep copy of the graph rooted at `node`. The test
    # will serialize the cloned graph back to an adjacency list.

    return _graph_to_adj_list(node)

